/////////////////////////////////
// cp_fflags_set_m
//   Set each flag with different operations
/////////////////////////////////
  CSRW(fcsr, zero)    # clear all flags and rounding mode before starting
  RVTEST_TESTDATA_LOAD_FLOAT_SINGLE(x3, f10) # load 0.0: f10 = 0x00000000
  RVTEST_TESTDATA_LOAD_FLOAT_SINGLE(x3, f11) # load 1.0: f11 = 0x3f800000
  RVTEST_TESTDATA_LOAD_FLOAT_SINGLE(x3, f12) # load 3.0: f12 = 0x40400000
  RVTEST_TESTDATA_LOAD_FLOAT_SINGLE(x3, f13) # load inf: f13 = 0x7f800000
  RVTEST_TESTDATA_LOAD_FLOAT_SINGLE(x3, f14) # load tiny: f14 = 0x00800000
  RVTEST_TESTDATA_LOAD_FLOAT_SINGLE(x3, f15) # load max: f15 = 0x7f7fffff

  csrwi fflags, 0 # reset flags
ZicsrF_cg_cp_fflags_set_m_NV:
  fsub.s f7, f13, f13           # inf - inf sets invalid flag
  # Check if f7 contains the expected result. Also checks fflags. x2 is the signature ptr, x5 is the link ptr, x4 is a temp reg, f4 is a floating point temp reg.
  RVTEST_SIGUPD_F(x2, x5, x4, f4, f7, ZicsrF_cg_cp_fflags_set_m_NV, ZicsrF_cg_cp_fflags_set_m_NV_str)

  csrwi fflags, 0 # reset flags
ZicsrF_cg_cp_fflags_set_m_DZ:
  fdiv.s f7, f11, f10           # 1 / 0  sets divide by zero
  # Check if f7 contains the expected result. Also checks fflags. x2 is the signature ptr, x5 is the link ptr, x4 is a temp reg, f4 is a floating point temp reg.
  RVTEST_SIGUPD_F(x2, x5, x4, f4, f7, ZicsrF_cg_cp_fflags_set_m_DZ, ZicsrF_cg_cp_fflags_set_m_DZ_str)

  csrwi fflags, 0 # reset flags
ZicsrF_cg_cp_fflags_set_m_OF:
  fadd.s f7, f15, f15           # big + big sets overflow flag
  # Check if f7 contains the expected result. Also checks fflags. x2 is the signature ptr, x5 is the link ptr, x4 is a temp reg, f4 is a floating point temp reg.
  RVTEST_SIGUPD_F(x2, x5, x4, f4, f7, ZicsrF_cg_cp_fflags_set_m_OF, ZicsrF_cg_cp_fflags_set_m_OF_str)

  csrwi fflags, 0 # reset flags
ZicsrF_cg_cp_fflags_set_m_UF:
  fmul.s f7, f14, f14           # tiny * tiny sets underflow flag
  # Check if f7 contains the expected result. Also checks fflags. x2 is the signature ptr, x5 is the link ptr, x4 is a temp reg, f4 is a floating point temp reg.
  RVTEST_SIGUPD_F(x2, x5, x4, f4, f7, ZicsrF_cg_cp_fflags_set_m_UF, ZicsrF_cg_cp_fflags_set_m_UF_str)

  csrwi fflags, 0 # reset flags
ZicsrF_cg_cp_fflags_set_m_NX:
  fdiv.s f7, f11, f12           # 1 / 3 sets inexact flag
  # Check if f7 contains the expected result. Also checks fflags. x2 is the signature ptr, x5 is the link ptr, x4 is a temp reg, f4 is a floating point temp reg.
  RVTEST_SIGUPD_F(x2, x5, x4, f4, f7, ZicsrF_cg_cp_fflags_set_m_NX, ZicsrF_cg_cp_fflags_set_m_NX_str)


